    conversions = {
        "meters": length,
        "feet": length * 3.28084,
        "kilometers": length * 1000.0
    }
    supported_units = {"meters", "feet", "kilometers"}
    if unit not in supported_units:
        raise ValueError(f"Unsupported unit: {unit}")
    return conversions[unit]
