import pandas as pd
def simulate_temperature_reading():
    sensor_readings = {
        "Sensor_A": 25.0,
        "Sensor_B": 30.5,
        "Sensor_C": 15.2,
        "Sensor_D": 22.8
    }
    data = []
    for sensor, celsius in sensor_readings.items():
        kelvin = celsius + 273.15
        data.append({
            "Sensor": sensor,
            "Celsius": celsius,
            "Kelvin": kelvin
        })
    df = pd.DataFrame(data)
    print("Temperature Data Simulation")
    print("-------------------------")
    print(df.to_string(index=False))
if __name__ == '__main__':
    simulate_temperature_reading()

class Sensor:
    def read_raw_temperature(self):
        return 25.5
class Converter:
    def celsius_to_fahrenheit(self, celsius):
        return (celsius * 9/5) + 32
class TemperatureSystem:
    def __init__(self):
        self.sensor = Sensor()
        self.converter = Converter()
    def get_temperature_in_fahrenheit(self):
        raw_temp = self.sensor.read_raw_temperature()
        fahrenheit = self.converter.celsius_to_fahrenheit(raw_temp)
        return fahrenheit
if __name__ == '__main__':
    system = TemperatureSystem()
    fahrenheit_temp = system.get_temperature_in_fahrenheit()
    print(fahrenheit_temp)

import csv
def celsius_to_fahrenheit(celsius):
    return (celsius * 9/5) + 32
def process_temperature_data(input_filename, output_filename):
    try:
        with open(input_filename, mode='r', newline='') as infile:
            reader = csv.reader(infile)
            header = next(reader, None)
            if header is None:
                return
            output_data = [header + ["Fahrenheit"]]
            for row in reader:
                if len(row) > 0:
                    try:
                        celsius = float(row[0].strip())
                        fahrenheit = celsius_to_fahrenheit(celsius)
                        output_data.append([row[0].strip(), row[1].strip(), f"{fahrenheit:.2f}"])
                    except ValueError:
                        print(f"Skipping invalid temperature reading: {row}")
                else:
                    output_data.append(["", "Error", "No data"])
        with open(output_filename, mode='w', newline='') as outfile:
            writer = csv.writer(outfile)
            writer.writerows(output_data)
    except FileNotFoundError:
        print(f"Error: Input file '{input_filename}' not found.")
    except IOError as e:
        print(f"An I/O error occurred: {e}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
