        print(f"Error: {e}")
    shape2 = Shape(-5, 10)
    try:
        shape2.compare_lengths()
        print("Lengths are valid.")
    except LengthError as e:
        print(f"Error: {e}")
    shape3 = Shape(10, 5000000)
    try:
        shape3.compare_lengths()
        print("Lengths are valid.")
    except LengthError as e:
        print(f"Error: {e}")

class LengthComparisonError(Exception):
    pass
class Shape:
    def __init__(self, length1, length2):
        self.length1 = length1
        self.length2 = length2
    def compare_lengths(self):
        if self.length1 < 0 or self.length2 < 0:
            raise LengthComparisonError("One or both lengths cannot be negative.")
        if abs(self.length1 - self.length2) > 1000000:
            raise LengthComparisonError("Lengths are impossibly different.")
if __name__ == '__main__':
    shape1 = Shape(10, 5)
    try:
        shape1.compare_lengths()
        print("Comparison successful for (10, 5)")
    except LengthComparisonError as e:
        print(f"Error: {e}")
    shape2 = Shape(-5, 10)
    try:
        shape2.compare_lengths()
        print("Comparison successful for (-5, 10)")
    except LengthComparisonError as e:
        print(f"Error: {e}")
    shape3 = Shape(10000000, 10)
    try:
        shape3.compare_lengths()
        print("Comparison successful for (10000000, 10)")
    except LengthComparisonError as e:
        print(f"Error: {e}")

def compare_lengths(length1, length2):
    absolute_difference = abs(length1 - length2)
    if length1 == 0 and length2 == 0:
        percentage_difference = 0.0
    elif length1 == 0 or length2 == 0:
        if length1 == 0:
            percentage_difference = float('inf') if length2 != 0 else 0.0
        else:
            percentage_difference = float('inf')
    else:
        if length1 != 0:
            percentage_difference = (absolute_difference / length1) * 100
        else:
            percentage_difference = (absolute_difference / length2) * 100
    return absolute_difference, percentage_difference
if __name__ == '__main__':
    sample_length1 = 150.5
    sample_length2 = 175.2
    diff, percent_diff = compare_lengths(sample_length1, sample_length2)
    print(f"Length 1: {sample_length1}")
    print(f"Length 2: {sample_length2}")
    print("-" * 30)
    print(f"Absolute Difference: {diff}")
    print(f"Percentage Difference: {percent_diff:.2f}%")

