class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius
    def calculate_area(self):
        import math
        return math.pi * self.radius**2
if __name__ == '__main__':
    rectangle = Rectangle(10, 5)
    circle = Circle(7)
    print("Rectangle Area:", rectangle.calculate_area())
    print("Circle Area:", circle.calculate_area())

import math
def calculate_area(shape_data):
    shape_type = shape_data.get("type")
    params = shape_data.get("params", {})
    if shape_type == "rectangle":
        length = params.get("length")
        width = params.get("width")
        if length is not None and width is not None:
            return length * width
    elif shape_type == "circle":
        radius = params.get("radius")
        if radius is not None:
            return math.pi * (radius ** 2)
    elif shape_type == "triangle":
        base = params.get("base")
        height = params.get("height")
        if base is not None and height is not None:
            return 0.5 * base * height
    elif shape_type == "square":
        side = params.get("side")
        if side is not None:
            return side * side
    else:
        return None
if __name__ == '__main__':
    shapes = [
        {"type": "rectangle", "params": {"length": 10, "width": 5}},
        {"type": "circle", "params": {"radius": 4}},
        {"type": "triangle", "params": {"base": 8, "height": 6}},
        {"type": "square", "params": {"side": 7}},
        {"type": "unknown", "params": {}}
    ]
    for shape in shapes:
        area = calculate_area(shape)
        print(f"Shape Type: {shape.get('type')}, Area: {area}")

