import math
def volume_to_liters(volume: float, unit: str) -> float:
    if unit.lower() == "liter":
        return volume
    elif unit.lower() == "l":
        return volume
    elif unit.lower() == "ml":
        return volume / 1000.0
    elif unit.lower() == "milliliter":
        return volume / 1000.0
    elif unit.lower() == "cm3":
        return volume / 1000000.0
    elif unit.lower() == "cc":
        return volume / 1000.0
    elif unit.lower() == "m3":
        return volume * 1000.0
    elif unit.lower() == "cubic meter":
        return volume * 1000.0
    elif unit.lower() == "cubic meter":
        return volume * 1000.0
    else:
        raise ValueError(f"Unsupported unit: {unit}")
