            print(f"An unexpected error occurred for {volume} {unit}: {e}")

class VolumeConverter:
    def __init__(self):
        self.conversion_factors = {
            "L_to_ml": 1000.0,
            "m3_to_L": 1000.0,
            "m3_to_gal": 264.172,
            "L_to_gal": 0.264172
        }
    def convert(self, value, from_unit, to_unit):
