def simplify_ratios(pairs):
    simplified = []
    for a, b in pairs:
        import math
        if b == 0:
            simplified.append((float('inf'), 0.0))
        else:
            common = math.gcd(a, b)
            simplified.append((a // common, b // common))
    return simplified
