    distribution = {}
    if total_weight == 0:
        for item in ratios:
            distribution[item] = 0.0
        return distribution
    total_ratio = sum(ratios.values())
    if total_ratio == 0:
        for item in ratios:
            distribution[item] = 0.0
        return distribution
    for item, ratio in ratios.items():
        if ratio != 0:
            actual_weight = (ratio / total_ratio) * total_weight
            distribution[item] = actual_weight
