def convert_ratios_to_weights(ratios, total_weight):
    weights = {}
    if not ratios:
        return weights
    sum_ratios = sum(ratios)
    if sum_ratios == 0:
        raise ValueError("Sum of ratios cannot be zero")
    for ratio in ratios:
        weight = (ratio / sum_ratios) * total_weight
        weights[ratio] = weight
    return weights
