def convert_ratios_to_weights(ratios, total_weight):
    if not ratios:
        return []
    sum_ratios = sum(ratios)
    if sum_ratios == 0:
        return [0.0] * len(ratios)
    weights = []
    for ratio in ratios:
        weight = (ratio / sum_ratios) * total_weight
        weights.append(weight)
    return weights
