import datetime
def calculate_total_elapsed_time(timestamps):
    if not timestamps:
        return None
    datetime_objects = [datetime.datetime.fromisoformat(ts) for ts in timestamps]
    earliest = min(datetime_objects)
    latest = max(datetime_objects)
    time_difference = latest - earliest
    return time_difference
if __name__ == '__main__':
    sample_timestamps = [
        "2023-01-01T10:00:00",
        "2023-01-05T12:30:00",
        "2023-01-03T08:00:00"
    ]
    elapsed_time = calculate_total_elapsed_time(sample_timestamps)
    if elapsed_time:
        print(elapsed_time)
    else:
        print("List of timestamps is empty")

import math
def simplify_ratio(numerator, denominator):
    if denominator == 0:
        raise ValueError("Denominator cannot be zero")
    if numerator == 0:
        return 0, 1
    common = math.gcd(abs(numerator), abs(denominator))
    simplified_num = numerator // common
    simplified_den = denominator // common
    if simplified_den < 0:
        simplified_num = -simplified_num
        simplified_den = -simplified_den
    return simplified_num, simplified_den
def calculate_ratio(a, b):
    if b == 0:
        raise ZeroDivisionError("Denominator cannot be zero")
    return a / b
def find_greatest_common_divisor(a, b):
    return math.gcd(a, b)
def find_least_common_multiple(a, b):
    if a == 0 or b == 0:
        return 0
    return abs(a * b) // find_greatest_common_divisor(a, b)
def ratio_to_fraction(ratio):
    if ratio == 0:
        return 0, 1
    numerator = int(ratio * 1000000)
    denominator = 1000000
    return simplify_ratio(numerator, denominator)
if __name__ == '__main__':
    print("--- Ratio Simplification ---")
    num1, den1 = 12, 18
    s_num, s_den = simplify_ratio(num1, den1)
    print(f"Simplifying {num1}/{den1}: {num1}/{den1} -> {s_num}/{s_den}")
    num2, den2 = 100, 75
    s_num, s_den = simplify_ratio(num2, den2)
    print(f"Simplifying {num2}/{den2}: {num2}/{den2} -> {s_num}/{s_den}")
    print("\n--- Ratio Calculation ---")
    a, b = 20, 5
    ratio = calculate_ratio(a, b)
    print(f"Calculating {a}/{b}: {a}/{b} = {ratio}")
    a, b = 10, 0
    try:
        calculate_ratio(a, b)
    except ZeroDivisionError as e:
        print(f"Error caught for {a}/{b}: {e}")
    print("\n--- GCD and LCM ---")
    x, y = 48, 18
    gcd_val = find_greatest_common_divisor(x, y)
    lcm_val = find_least_common_multiple(x, y)
    print(f"GCD of {x} and {y}: {gcd_val}")
    print(f"LCM of {x} and {y}: {lcm_val}")
    print("\n--- Ratio to Fraction Conversion (Example) ---")
    ratio_val = 1.25
    num_frac, den_frac = ratio_to_fraction(ratio_val)
    print(f"Converting {ratio_val} to fraction (scaled by 1,000,000): {num_frac}/{den_frac}")

import re
from datetime import timedelta
def parse_time_string(time_str):
    total_seconds = 0
    parts = time_str.lower().split()
    for part in parts:
        if part.isdigit():
            try:
                value = int(part)
                if 'hour' in parts or 'hr' in parts:
                    total_seconds += value * 3600
                elif 'minute' in parts or 'min' in parts:
                    total_seconds += value * 60
                elif 'second' in parts or 'sec' in parts:
                    total_seconds += value
            except ValueError:
                continue
        elif 'hours' in parts or 'hr' in parts:
            try:
                index = parts.index('hours') if 'hours' in parts else parts.index('hr')
                if index + 1 < len(parts) and parts[index + 1].isdigit():
                    total_seconds += int(parts[index + 1]) * 3600
            except (ValueError, IndexError):
                continue
        elif 'minutes' in parts or 'min' in parts:
            try:
                index = parts.index('minutes') if 'minutes' in parts else parts.index('min')
                if index + 1 < len(parts) and parts[index + 1].isdigit():
                    total_seconds += int(parts[index + 1]) * 60
            except (ValueError, IndexError):
                continue
        elif 'seconds' in parts or 'sec' in parts:
            try:
                index = parts.index('seconds') if 'seconds' in parts else parts.index('sec')
                if index + 1 < len(parts) and parts[index + 1].isdigit():
                    total_seconds += int(parts[index + 1])
            except (ValueError, IndexError):
                continue
    return total_seconds
def calculate_total_minutes(time_list):
    total_minutes = 0
    for time_str in time_list:
        total_seconds = parse_time_string(time_str)
        total_minutes += total_seconds / 60
    return total_minutes
if __name__ == '__main__':
    time_differences = [
        '2 hours 30 minutes',
        '1 day',
        '45 minutes',
        '1 hour 15 minutes',
        '30 seconds'
    ]
    total_minutes = calculate_total_minutes(time_differences)
    print(f"Time differences provided: {time_differences}")
    print(f"Total elapsed time in minutes: {total_minutes}")

