        if unit == "hours":
            total_seconds += value * 3600
        elif unit == "minutes":
            total_seconds += value * 60
        elif unit == "seconds":
            total_seconds += value
    return total_seconds
if __name__ == '__main__':
    sample_times = [
        "1 hour 30 minutes",
        "2 hours",
        "10 minutes",
        "3600 seconds",
        "5 minutes 10 seconds"
    ]
    total = aggregate_time_differences(sample_times)
    print(total)

def calculate_net_time_difference(time_string, delimiter=';'):
    time_points = []
    if not time_string:
        return 0
    time_segments = time_string.split(delimiter)
    for segment in time_segments:
        try:
            time_points.append(float(segment.strip()))
        except ValueError:
            continue
    if not time_points:
        return 0
    min_time = min(time_points)
    max_time = max(time_points)
    return max_time - min_time
if __name__ == '__main__':
    sample_time_string = "10:00;15:30;09:15;11:00"
    result = calculate_net_time_difference(sample_time_string)
    print(result)

