    print(f"Comparing {num1} and {num3}: {compare_large_integers(num1, num3)}")
    print(f"Comparing {num2} and {num1}: {compare_large_integers(num2, num1)}")
    print(f"Comparing {num4} and {num4}: {compare_large_integers(num4, num4)}")

