def recursive_equality(a, b):
    if type(a) != type(b):
        return False
    if isinstance(a, dict):
        if len(a) != len(b):
            return False
        for key in a:
            if key not in b:
                return False
            if not recursive_equality(a[key], b[key]):
                return False
        return True
    elif isinstance(a, list):
        if len(a) != len(b):
            return False
        for i in range(len(a)):
            if not recursive_equality(a[i], b[i]):
                return False
        return True
    else:
        return a == b
