    dict2 = {'a': 1, 'b': [2, 3]}
    dict3 = {'a': 1, 'b': [2, 4]}
    dict4 = {'a': 1, 'b': [2, 3, 4]}
    dict5 = {'a': 1}
    print(f"list1 == list2: {recursive_equality(list1, list2)}")
    print(f"list1 == list3: {recursive_equality(list1, list3)}")
    print(f"list1 == list4: {recursive_equality(list1, list4)}")
    print(f"list1 == list5: {recursive_equality(list1, list5)}")
    print(f"list1 == list6: {recursive_equality(list1, list6)}")
