    data1 = [('apple', 5), ('banana', 2), ('cherry', 8)]
    def key1(item):
        return item[1]
    sorted_data1 = sorter.sort_data(data1, key1)
    print("Sorted Data 1:")
    print(sorted_data1)
    data2 = [('a', 3), ('b', 1), ('c', 2)]
