def check_threshold(threshold):
    def decorator(func):
        def wrapper(*args):
            result = func(*args)
            if result == threshold:
                raise ValueError("Result equals the specified threshold")
            return result
        return wrapper
    return decorator
@check_threshold(10)
def calculate_difference(a, b):
    return a - b
