    output = swap_adjacent(sample_input)
    print(output)

def swap_even_odd(s):
    n = len(s)
    if n == 0:
        return ""
    chars = list(s)
    for i in range(0, n - 1, 2):
        if i + 1 < n:
            chars[i], chars[i+1] = chars[i+1], chars[i]
    return "".join(chars)
