def capitalize_first_letter_only(text):
    result = []
    capitalize_next = True
    for char in text:
        if char.isalpha():
            if capitalize_next:
                result.append(char.upper())
                capitalize_next = False
            else:
                result.append(char.lower())
        else:
            result.append(char)
            if char.isspace():
                capitalize_next = True
            else:
                capitalize_next = False
    return "".join(result)
