        return text.capitalize()
    elif rule == 'upper':
        return text.upper()
    elif rule == 'lower':
        return text.lower()
    elif rule == 'title_char':
        if text:
            return text[0].upper() + text[1:]
        else:
            return ""
    else:
        return text
