        manipulation_rule = sys.argv[1] if len(sys.argv) > 1 else sample_rule
        result = apply_case_manipulation(input_string, manipulation_rule)
        print(result)
    except ValueError as e:
        print(f"Error: {e}", file=sys.stderr)
    except Exception as e:
