import sys
def apply_case_manipulation(text, rule):
    if rule == 'swap':
        return text[::-1]
    elif rule == 'reverse':
        return text[::-1]
    elif rule == 'upper':
        return text.upper()
    elif rule == 'lower':
        return text.lower()
    else:
        raise ValueError(f"Unknown manipulation rule: {rule}")
if __name__ == '__main__':
