def calculate_circle_area(diameter):
    if diameter <= 0:
        raise ValueError("Diameter must be a positive number")
    radius = diameter / 2
    area = 3.141592653589793 * (radius ** 2)
    return area
if __name__ == '__main__':
    try:
        diameter1 = 10
        area1 = calculate_circle_area(diameter1)
        print(f"The area of a circle with diameter {diameter1} is: {area1}")
        diameter2 = 0
        area2 = calculate_circle_area(diameter2)
    except ValueError as e:
        print(f"Error: {e}")
    try:
        diameter3 = -5
        area3 = calculate_circle_area(diameter3)
    except ValueError as e:
        print(f"Error: {e}")

def circle_area_validator(func):
    def wrapper(*args, **kwargs):
        radius = args[0]
        if not isinstance(radius, (int, float)) or radius <= 0:
            raise ValueError("Radius must be a positive number.")
        return func(*args, **kwargs)
    return wrapper
@circle_area_validator
def calculate_circle_area(radius):
    return 3.14159 * radius * radius
if __name__ == '__main__':
    print(calculate_circle_area(5))
    try:
        calculate_circle_area(-2)
    except ValueError as e:
        print(f"Error: {e}")
    try:
        calculate_circle_area("a")
    except ValueError as e:
        print(f"Error: {e}")

def validate_radius(radius):
    if radius <= 0:
        raise ValueError("Radius must be positive")
    return radius
class CircleAreaContext:
    def __init__(self, radius):
        self.radius = radius
    def __enter__(self):
        validated_radius = validate_radius(self.radius)
        return validated_radius
    def __exit__(self, exc_type, exc_val, exc_tb):
        pass
def calculate_circle_area(radius):
    validated_radius = validate_radius(radius)
    return 3.14159 * validated_radius ** 2
def area_decorator(func):
    def wrapper(*args):
        if len(args) == 1:
            radius = args[0]
            try:
                result = func(validate_radius(radius))
                return result
            except ValueError as e:
                raise e
        else:
            return func(*args)
    return wrapper
@area_decorator
def calculate_area_decorated(radius):
    return 3.14159 * radius ** 2
