class Triangle:
    def __init__(self, a, b, c):
        self.a = a
        self.b = b
        self.c = c
    def calculate_perimeter(self):
        return self.a + self.b + self.c
if __name__ == '__main__':
    t = Triangle(3, 4, 5)
    perimeter = t.calculate_perimeter()
    print(perimeter)

def calculate_triangle_perimeter(a, b, c):
    if a <= 0 or b <= 0 or c <= 0:
        raise ValueError("Side lengths must be positive.")
    if not (a + b > c and a + c > b and b + c > a):
        raise ValueError("The given side lengths do not form a valid triangle.")
    return a + b + c
if __name__ == '__main__':
    try:
        result1 = calculate_triangle_perimeter(3, 4, 5)
        print(f"Perimeter of (3, 4, 5): {result1}")
    except ValueError as e:
        print(f"Error: {e}")
    try:
        result2 = calculate_triangle_perimeter(1, 2, 3)
        print(f"Perimeter of (1, 2, 3): {result2}")
    except ValueError as e:
        print(f"Error: {e}")
    try:
        result3 = calculate_triangle_perimeter(-1, 2, 3)
        print(f"Perimeter of (-1, 2, 3): {result3}")
    except ValueError as e:
        print(f"Error: {e}")
    try:
        result4 = calculate_triangle_perimeter(1, 1, 10)
        print(f"Perimeter of (1, 1, 10): {result4}")
    except ValueError as e:
        print(f"Error: {e}")

