import math
def calculate_triangle_sides(a, b, c):
    hypotenuse = max(a, b, c)
    leg1 = min(a, b, c)
    leg2 = (a + b + c) - hypotenuse
    if hypotenuse * hypotenuse == leg1 * leg1 + leg2 * leg2:
        return leg1, leg2, hypotenuse
    else:
        return None
