        with self.assertRaisesRegex(ValueError, "Length and width must be non-negative"):
            calculate_perimeter(-5, 10)
        with self.assertRaisesRegex(ValueError, "Length and width must be non-negative"):
            calculate_perimeter(5, -10)
        with self.assertRaisesRegex(ValueError, "Length and width must be non-negative"):
            calculate_perimeter(-5, -10)
