import sys
def calculate_area(shape, length, width, radius, base, height):
    if shape == "rectangle":
        return length * width
    elif shape == "circle":
        return 3.14159 * radius * radius
    elif shape == "triangle":
        return 0.5 * base * height
    else:
        return None
