        return dimensions['side'] ** 2
    elif shape == 'circle':
        radius = dimensions['radius']
        import math
        return math.pi * (radius ** 2)
    elif shape == 'rectangle':
        return dimensions['length'] * dimensions['width']
    else:
        raise ValueError("Unknown shape")
